// src/constants.ts
var CIRCLE_BATCHING_NAME = "GatewayWalletBatched";
var CIRCLE_BATCHING_VERSION = "1";
var CIRCLE_BATCHING_SCHEME = "exact";
var GATEWAY_MIN_AUTH_VALIDITY_SECONDS = 7 * 24 * 60 * 60;
var GATEWAY_AUTH_VALIDITY_BUFFER_SECONDS = 100;
var GATEWAY_AUTH_VALIDITY_WINDOW_SECONDS = GATEWAY_MIN_AUTH_VALIDITY_SECONDS + GATEWAY_AUTH_VALIDITY_BUFFER_SECONDS;
var ARC_PRIVATE_MAINNET_HEADER = "X-ARC-PRIVATE-MAINNET-ENABLED";
function arcPrivateMainnetHeaders(arcPrivateMainnet) {
  if (!arcPrivateMainnet) {
    return {};
  }
  return { [ARC_PRIVATE_MAINNET_HEADER]: "true" };
}

// src/detection.ts
function supportsBatching(requirements) {
  const extra = requirements.extra;
  if (!extra) {
    return false;
  }
  return extra.name === CIRCLE_BATCHING_NAME && extra.version === CIRCLE_BATCHING_VERSION;
}
function getVerifyingContract(requirements) {
  if (!supportsBatching(requirements)) {
    return void 0;
  }
  const verifyingContract = requirements.extra?.verifyingContract;
  if (typeof verifyingContract === "string") {
    return verifyingContract;
  }
  return void 0;
}

// src/hooks.ts
function warnHookFailure(component, phase, label, error) {
  const detail = error instanceof Error ? error.message : String(error);
  console.warn(`[x402] ${component} ${phase} hook threw (${label}): ${detail}`);
}

// src/client/BatchEvmScheme.ts
var authorizationTypes = {
  TransferWithAuthorization: [
    { name: "from", type: "address" },
    { name: "to", type: "address" },
    { name: "value", type: "uint256" },
    { name: "validAfter", type: "uint256" },
    { name: "validBefore", type: "uint256" },
    { name: "nonce", type: "bytes32" }
  ]
};
function createNonce() {
  const bytes = new Uint8Array(32);
  crypto.getRandomValues(bytes);
  return `0x${Array.from(bytes).map((b) => b.toString(16).padStart(2, "0")).join("")}`;
}
var BatchEvmScheme = class {
  /**
   * Creates a new BatchEvmScheme.
   *
   * @param signer - The EVM signer for signing payment authorizations
   */
  constructor(signer) {
    this.signer = signer;
  }
  scheme = CIRCLE_BATCHING_SCHEME;
  beforePaymentCreationHooks = [];
  afterPaymentCreationHooks = [];
  onPaymentCreationFailureHooks = [];
  paymentResponseHooks = [];
  /**
   * Register a hook that runs before payment payload creation. Returning
   * `{ abort: true, reason }` causes `createPaymentPayload` to throw
   * `Error("Payment creation aborted: <reason>")`.
   */
  onBeforePaymentCreation(hook) {
    this.beforePaymentCreationHooks.push(hook);
    return this;
  }
  /**
   * Register a hook that runs after a successful payment payload creation.
   */
  onAfterPaymentCreation(hook) {
    this.afterPaymentCreationHooks.push(hook);
    return this;
  }
  /**
   * Register a hook that runs when payload creation throws. Return
   * `{ recovered: true, payload }` to swallow the error and use the
   * provided payload as the result instead.
   */
  onPaymentCreationFailure(hook) {
    this.onPaymentCreationFailureHooks.push(hook);
    return this;
  }
  /**
   * Register a hook that runs after the buyer's paid HTTP request completes.
   * Hooks fire when {@link dispatchPaymentResponse} is called by the
   * transport. Return `{ recovered: true }` to instruct the transport to
   * retry with a fresh payload.
   */
  onPaymentResponse(hook) {
    this.paymentResponseHooks.push(hook);
    return this;
  }
  /**
   * Fire all registered `onPaymentResponse` hooks in order. Returns
   * `{ recovered: true }` if any hook signals recovery (first wins).
   *
   * Transport wrappers should call this after the paid HTTP request settles
   * — see `x402HTTPClient.processPaymentResult` in the standard SDK.
   */
  async dispatchPaymentResponse(context) {
    for (const [index, hook] of this.paymentResponseHooks.entries()) {
      try {
        const result = await hook(context);
        if (result && "recovered" in result && result.recovered) {
          return { recovered: true };
        }
      } catch (err) {
        warnHookFailure(
          "BatchEvmScheme",
          "onPaymentResponse",
          `manual hook #${index}`,
          err
        );
      }
    }
    return void 0;
  }
  /**
   * Creates a payment payload for Circle batching.
   *
   * @param x402Version - The x402 protocol version
   * @param paymentRequirements - The payment requirements (must be a Circle batching option)
   * @returns Promise resolving to the payment payload
   * @throws Error if requirements are not a Circle batching option
   */
  async createPaymentPayload(x402Version, paymentRequirements) {
    const context = {
      paymentRequired: this.synthesizePaymentRequired(x402Version, paymentRequirements),
      selectedRequirements: paymentRequirements
    };
    for (const hook of this.beforePaymentCreationHooks) {
      const result = await hook(context);
      if (result && "abort" in result && result.abort) {
        throw new Error(`Payment creation aborted: ${result.reason}`);
      }
    }
    try {
      if (!supportsBatching(paymentRequirements)) {
        throw new Error(
          `BatchEvmScheme can only handle Circle batching options. Expected extra.name="${CIRCLE_BATCHING_NAME}" and extra.version="${CIRCLE_BATCHING_VERSION}"`
        );
      }
      const verifyingContract = getVerifyingContract(paymentRequirements);
      if (!verifyingContract) {
        throw new Error(
          "Circle batching option missing extra.verifyingContract (GatewayWallet address)"
        );
      }
      const nonce = createNonce();
      const now = Math.floor(Date.now() / 1e3);
      const validityWindowSeconds = Math.max(
        paymentRequirements.maxTimeoutSeconds,
        GATEWAY_AUTH_VALIDITY_WINDOW_SECONDS
      );
      const authorization = {
        from: this.signer.address,
        to: getAddress(paymentRequirements.payTo),
        value: paymentRequirements.amount,
        validAfter: (now - 600).toString(),
        // 10 minutes before
        // Clamp seller-published timeouts so the signed authorization is always
        // valid long enough for Gateway batching.
        validBefore: (now + validityWindowSeconds).toString(),
        nonce
      };
      const signature = await this.signAuthorization(
        authorization,
        paymentRequirements,
        verifyingContract
      );
      const payload = {
        authorization,
        signature
      };
      const partial = {
        x402Version,
        payload
      };
      const created = {
        x402Version,
        payload
      };
      const createdContext = {
        ...context,
        paymentPayload: created
      };
      for (const [index, hook] of this.afterPaymentCreationHooks.entries()) {
        try {
          await hook(createdContext);
        } catch (err) {
          warnHookFailure(
            "BatchEvmScheme",
            "afterPaymentCreation",
            `manual hook #${index}`,
            err
          );
        }
      }
      return partial;
    } catch (error) {
      const failureContext = {
        ...context,
        error
      };
      for (const hook of this.onPaymentCreationFailureHooks) {
        const result = await hook(failureContext);
        if (result && "recovered" in result && result.recovered) {
          return {
            x402Version: result.payload.x402Version,
            payload: result.payload.payload
          };
        }
      }
      throw error;
    }
  }
  /**
   * Sign the EIP-3009 authorization using EIP-712.
   * Uses the GatewayWallet contract as verifyingContract instead of USDC.
   */
  async signAuthorization(authorization, requirements, verifyingContract) {
    if (!requirements.network.startsWith("eip155:")) {
      throw new Error(
        `BatchEvmScheme: unsupported network format "${requirements.network}". Expected "eip155:<chainId>"`
      );
    }
    const chainId = parseInt(requirements.network.split(":")[1]);
    const domain = {
      name: CIRCLE_BATCHING_NAME,
      version: CIRCLE_BATCHING_VERSION,
      chainId,
      verifyingContract: getAddress(verifyingContract)
    };
    const message = {
      from: getAddress(authorization.from),
      to: getAddress(authorization.to),
      value: BigInt(authorization.value),
      validAfter: BigInt(authorization.validAfter),
      validBefore: BigInt(authorization.validBefore),
      nonce: authorization.nonce
    };
    return await this.signer.signTypedData({
      domain,
      types: authorizationTypes,
      primaryType: "TransferWithAuthorization",
      message
    });
  }
  /**
   * When `createPaymentPayload` is called directly (not through an x402Client),
   * we don't have a real PaymentRequired response. Synthesize a minimal one
   * so the hook context still carries the standard SDK's shape.
   */
  synthesizePaymentRequired(x402Version, requirements) {
    return {
      x402Version,
      accepts: [requirements]
    };
  }
};

// src/client/CompositeEvmScheme.ts
var CompositeEvmScheme = class {
  constructor(batchScheme, fallbackScheme) {
    this.batchScheme = batchScheme;
    this.fallbackScheme = fallbackScheme;
    if (fallbackScheme.scheme !== CIRCLE_BATCHING_SCHEME) {
      throw new Error(
        `CompositeEvmScheme: fallbackScheme.scheme must be "${CIRCLE_BATCHING_SCHEME}", got "${fallbackScheme.scheme}"`
      );
    }
  }
  scheme = CIRCLE_BATCHING_SCHEME;
  async createPaymentPayload(x402Version, paymentRequirements) {
    if (supportsBatching(paymentRequirements)) {
      return this.batchScheme.createPaymentPayload(x402Version, paymentRequirements);
    }
    return this.fallbackScheme.createPaymentPayload(x402Version, paymentRequirements);
  }
};

// src/client/register.ts
function registerBatchScheme(client, config) {
  const batchScheme = new BatchEvmScheme(config.signer);
  const schemeToRegister = config.fallbackScheme ? new CompositeEvmScheme(batchScheme, config.fallbackScheme) : batchScheme;
  const networks = config.networks ?? ["eip155:*"];
  for (const network of networks) {
    client.register(network, schemeToRegister);
  }
  return schemeToRegister;
}

